import Alpine from 'alpinejs';
import { db } from './firebase';
import { collection, query, where, getDocs, addDoc, onSnapshot, doc, updateDoc } from 'firebase/firestore';

declare global {
  interface Window {
    Alpine: any;
  }
}

// Make Alpine available globally
window.Alpine = Alpine;

document.addEventListener('alpine:init', () => {
  Alpine.data('app', () => ({
    route: window.location.pathname,
    phoneNumber: '',

    // Onboarding State
    onboardingStep: 1,
    registerName: '',
    registerTrade: '',
    registerCompany: '',
    registerArea: '',
    calloutFee: 50,
    filterStrictness: 3,
    loginError: '',
    isLoggingIn: false,

    // Vault State
    newVaultIdea: '',
    newVaultPhase: 3,
    vaultIdeas: [],
    unsubscribeVault: null,

    // Simulator State
    simState: 1,
    simMessages: [],
    simInput: '',
    simFilterStrength: 3,

    // Calculator variables
    hoursWasted: 5,
    milesDriven: 50,
    hourlyRate: 45,
    fuelCost: 0.45,
    showModal: null,
    get adminDebt() { return Math.round((this.hoursWasted * this.hourlyRate + this.milesDriven * this.fuelCost) * 52); },

    // Dashboard variables
    activeTab: 'money', // 'money' | 'safety' | 'business'
    leads: [],
    isLoadingLeads: false,
    selectedLead: null,
    isLeadModalOpen: false,
    unsubscribeLeads: null,

    get moneyLeads() {
        return this.leads.filter((l: any) => l.status === 'qualified');
    },

    get safetyLeads() {
        return this.leads.filter((l: any) => l.status === 'archived');
    },

    init() {
      window.addEventListener('popstate', () => {
        this.route = window.location.pathname;
        this.handleRouteLogic();
      });

      this.handleRouteLogic();
    },

    handleRouteLogic() {
      if (this.route === '/dashboard') {
        this.subscribeLeads();
      } else {
        this.unsubscribeLeadsListener();
      }

      if (this.route === '/vault') {
        this.subscribeVault();
      } else {
        this.unsubscribeVaultListener();
      }

      if (this.route === '/') {
